import { html, customElement, state } from '@umbraco-cms/backoffice/external/lit';
import { UmbModalBaseElement, UMB_MODAL_MANAGER_CONTEXT } from '@umbraco-cms/backoffice/modal';
import { UMB_FOLDER_CREATE_MODAL } from '@umbraco-cms/backoffice/tree';
import { UMB_ACTION_EVENT_CONTEXT } from '@umbraco-cms/backoffice/action';
import type { FormTemplateBase } from '@umbraco-forms/generated';
import { UmbRequestReloadChildrenOfEntityEvent } from '@umbraco-cms/backoffice/entity-action';
import { FORMS_FORM_FOLDER_DETAIL_REPOSITORY_ALIAS, FormsFormDetailRepository } from '../../../repository/index.js';
import { FORMS_FORM_FOLDER_ENTITY_TYPE, FORMS_FORM_ROOT_ENTITY_TYPE } from '../../../entities.js';
import type { FormsFormCreateOptionsModalData } from './index.js';

@customElement('forms-form-create-options-modal')
export class FormsFormCreateOptionsModalElement extends UmbModalBaseElement<FormsFormCreateOptionsModalData> {

	#formDetailRepository = new FormsFormDetailRepository(this);

	@state()
	private _templates: Array<FormTemplateBase> = [];

	async connectedCallback() {
		super.connectedCallback();

		const { data } = await this.#formDetailRepository.requestTemplates();
		if (data) {
			this._templates = data;
		}
	}

	async #createFolder(event: PointerEvent) {
		event.stopPropagation();
		if (!this.data?.parent) throw new Error('A parent is required to create a form');

		const modalManager = await this.getContext(UMB_MODAL_MANAGER_CONTEXT);
		const folderModalHandler = modalManager.open(this, UMB_FOLDER_CREATE_MODAL, {
			data: {
				folderRepositoryAlias: FORMS_FORM_FOLDER_DETAIL_REPOSITORY_ALIAS,
				parent: this.data.parent,
			},
		});

		const parent = this.data.parent;
		folderModalHandler?.onSubmit().then(async () => {
			this._submitModal();

			const reloadEvent = new UmbRequestReloadChildrenOfEntityEvent({
				entityType: parent.unique ? FORMS_FORM_FOLDER_ENTITY_TYPE : FORMS_FORM_ROOT_ENTITY_TYPE,
				unique: parent.unique,
			});

			const eventContext = await this.getContext(UMB_ACTION_EVENT_CONTEXT);
			eventContext.dispatchEvent(reloadEvent);
		}).catch(() => undefined);
	}

	#getCreateHref(template?: FormTemplateBase) {
		let href = `section/forms/workspace/form/create/parent/${this.data?.parent.entityType}/${
			this.data?.parent.unique || 'null'
		}`;
		if (template) {
			href = href.replace("/create/", "/createFromTemplate/") + "/" + template.alias;
		}

		return href;
	}

	render() {
		return html`
			<umb-body-layout headline=${this.localize.term('formCreate_title')}>
				<uui-box>
					<uui-menu-item href=${this.#getCreateHref()} label=${this.localize.term('formCreate_newFormMenu')} @click=${this._submitModal}>
						<uui-icon slot="icon" name="icon-autofill"></uui-icon>
					</uui-menu-item>
					${this._templates.map((template) =>
						html`<uui-menu-item href=${this.#getCreateHref(template)} label="New ${template.name}..." @click=${this._submitModal}>
							<uui-icon slot="icon" name="icon-autofill"></uui-icon>
						</uui-menu-item>`
					)}
					<uui-menu-item @click=${this.#createFolder} label=${this.localize.term('formCreate_newFolderMenu')}>
						<uui-icon slot="icon" name="icon-folder"></uui-icon>
					</uui-menu-item>
				</uui-box>
				<uui-button slot="actions" id="cancel" label=${this.localize.term('general_cancel')} @click="${this._rejectModal}">${this.localize.term('general_cancel')}</uui-button>
			</umb-body-layout>
		`;
	}
}

export default FormsFormCreateOptionsModalElement;

declare global {
	interface HTMLElementTagNameMap {
		'forms-form-create-options-modal': FormsFormCreateOptionsModalElement;
	}
}
